import{_ as s,o,c as t,au as a}from"./chunks/framework.Bpqx6pAq.js";const g=JSON.parse('{"title":"Session","description":"","frontmatter":{},"headers":[],"relativePath":"api/core/utilities/utils.session.md","filePath":"api/core/utilities/utils.session.md"}'),r={name:"api/core/utilities/utils.session.md"};function i(n,e,c,l,d,u){return o(),t("div",null,[...e[0]||(e[0]=[a('<h1 id="session" tabindex="-1">Session <a class="header-anchor" href="#session" aria-label="Permalink to &quot;Session&quot;">​</a></h1><h2 id="overview" tabindex="-1">Overview <a class="header-anchor" href="#overview" aria-label="Permalink to &quot;Overview&quot;">​</a></h2><p>The <code>utils.session.js</code> module provides the core authentication and session management functions for KDK applications. It handles login, logout, session restoration, user ability computation, and remote logout synchronisation.</p><h2 id="functions" tabindex="-1">Functions <a class="header-anchor" href="#functions" aria-label="Permalink to &quot;Functions&quot;">​</a></h2><h3 id="async-login-email-password" tabindex="-1"><code>async login(email, password)</code> <a class="header-anchor" href="#async-login-email-password" aria-label="Permalink to &quot;`async login(email, password)`&quot;">​</a></h3><p>Authenticates the user with the local strategy, stores the user object in the global store, and computes their abilities.</p><ul><li><strong>Parameters:</strong><ul><li><code>email</code> <em>(string)</em>: The user&#39;s email address.</li><li><code>password</code> <em>(string)</em>: The user&#39;s password.</li></ul></li><li><strong>Returns:</strong> <code>Promise&lt;void&gt;</code></li></ul><h3 id="async-register-user" tabindex="-1"><code>async register(user)</code> <a class="header-anchor" href="#async-register-user" aria-label="Permalink to &quot;`async register(user)`&quot;">​</a></h3><p>Creates a new user account via the <code>users</code> service (removing <code>confirmPassword</code> first) and then logs them in.</p><ul><li><strong>Parameters:</strong><ul><li><code>user</code> <em>(Object)</em>: The user data object (must include <code>email</code> and <code>password</code>).</li></ul></li><li><strong>Returns:</strong> <code>Promise&lt;void&gt;</code></li></ul><h3 id="async-logout" tabindex="-1"><code>async logout()</code> <a class="header-anchor" href="#async-logout" aria-label="Permalink to &quot;`async logout()`&quot;">​</a></h3><p>Logs the user out: removes the cached authentication token, calls <code>api.logout()</code>, and clears the user from the global store.</p><ul><li><strong>Returns:</strong> <code>Promise&lt;void&gt;</code></li><li><strong>Throws:</strong> Re-throws service errors after cleaning up the local token.</li></ul><h3 id="async-restoresession" tabindex="-1"><code>async restoreSession()</code> <a class="header-anchor" href="#async-restoresession" aria-label="Permalink to &quot;`async restoreSession()`&quot;">​</a></h3><p>Restores a previous session. In offline (disconnected) mode, reads the cached authentication from <code>LocalCache</code>. Otherwise, calls <code>api.reAuthenticate()</code>. Throws if no valid session can be restored.</p><ul><li><strong>Returns:</strong> <code>Promise&lt;void&gt;</code></li><li><strong>Throws:</strong> <code>Error</code> if re-authentication fails.</li></ul><h3 id="async-updateabilities" tabindex="-1"><code>async updateAbilities()</code> <a class="header-anchor" href="#async-updateabilities" aria-label="Permalink to &quot;`async updateAbilities()`&quot;">​</a></h3><p>Recomputes the current user&#39;s abilities and stores them in <code>Store(&#39;user.abilities&#39;)</code>. Only updates the store if the computed rules have changed.</p><ul><li><strong>Returns:</strong> <code>Promise&lt;void&gt;</code></li></ul><h3 id="async-updateuser-user" tabindex="-1"><code>async updateUser(user)</code> <a class="header-anchor" href="#async-updateuser-user" aria-label="Permalink to &quot;`async updateUser(user)`&quot;">​</a></h3><p>Updates the stored user object and recomputes abilities if the given <code>user._id</code> matches the currently authenticated user.</p><ul><li><strong>Parameters:</strong><ul><li><code>user</code> <em>(Object)</em>: The patched user object received from the service.</li></ul></li><li><strong>Returns:</strong> <code>Promise&lt;void&gt;</code></li></ul><h3 id="async-logoutuser-user" tabindex="-1"><code>async logoutUser(user)</code> <a class="header-anchor" href="#async-logoutuser-user" aria-label="Permalink to &quot;`async logoutUser(user)`&quot;">​</a></h3><p>Performs a client-side-only logout in response to a remote logout event (e.g. the user logged out from another device). Clears local authentication state without making a service call.</p><ul><li><strong>Parameters:</strong><ul><li><code>user</code> <em>(Object)</em>: The user that was logged out.</li></ul></li><li><strong>Returns:</strong> <code>Promise&lt;void&gt;</code></li></ul><h3 id="subscribetouserchanges" tabindex="-1"><code>subscribeToUserChanges()</code> <a class="header-anchor" href="#subscribetouserchanges" aria-label="Permalink to &quot;`subscribeToUserChanges()`&quot;">​</a></h3><p>Registers <code>patched</code> and <code>logout</code> event handlers on the <code>users</code> service to keep the local user state in sync.</p><h3 id="unsubscribetouserchanges" tabindex="-1"><code>unsubscribeToUserChanges()</code> <a class="header-anchor" href="#unsubscribetouserchanges" aria-label="Permalink to &quot;`unsubscribeToUserChanges()`&quot;">​</a></h3><p>Removes the <code>patched</code> and <code>logout</code> event handlers registered by <code>subscribeToUserChanges()</code>.</p>',29)])])}const m=s(r,[["render",i]]);export{g as __pageData,m as default};
